def validate_url(url):
    """Validate URL format and ensure it uses secure protocols."""
    try:
        parsed = urlparse(url)
        if parsed.scheme not in ['https', 'http']:
            raise ValueError(f"Invalid scheme: {parsed.scheme}. Only http/https allowed.")
        if not parsed.netloc:
            raise ValueError("URL must include a valid hostname")
        return url
    except Exception as e:
        raise ValueError(f"Invalid URL format: {e}")


def validate_hostname(hostname):
    """Validate hostname format."""
    if not hostname or len(hostname) > 253:
        raise ValueError("Invalid hostname length")
    
    # Basic hostname validation
    allowed_chars = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789.-')
    if not all(c in allowed_chars for c in hostname):
        raise ValueError("Hostname contains invalid characters")
    
    parts = hostname.split('.')
    for part in parts:
        if not part or len(part) > 63:
            raise ValueError("Invalid hostname component")
        if part.startswith('-') or part.endswith('-'):
            raise ValueError("Hostname parts cannot start or end with hyphen")
    
    return hostname


def get_pip_config_path():
    """Get the appropriate pip configuration file path based on OS."""
    system = platform.system()
    
    if system == 'Windows':
        config_dir = Path(os.environ.get('APPDATA', '')) / 'pip'
        config_file = 'pip.ini'
    else:  # Unix-like (Linux, macOS)
        config_dir = Path.home() / '.config' / 'pip'
        config_file = 'pip.conf'
    
    return config_dir / config_file


def create_pip_config(
    internal_pypi_url,
    trusted_hosts=None,
    extra_index_urls=None,
    timeout=60,
    retries=5,
    cert_path=None
):
    """
    Create a secure pip configuration file.
    
    Args:
        internal_pypi_url: Primary internal PyPI mirror URL (must be HTTPS preferred)
        trusted_hosts: List of trusted hostnames (use sparingly, only for internal networks)
        extra_index_urls: Additional package index URLs
        timeout: Connection timeout in seconds
        retries: Number of retries for failed requests
        cert_path: Path to custom CA certificate bundle
    """
    
    # Validate primary index URL
    internal_pypi_url = validate_url(internal_pypi_url)
    
    # Validate extra index URLs
    if extra_index_urls:
        extra_index_urls = [validate_url(url) for url in extra_index_urls]
    
    # Validate trusted hosts
    validated_trusted_hosts = []
    if trusted_hosts:
        for host in trusted_hosts:
            validated_trusted_hosts.append(validate_hostname(host))
    
    # Validate certificate path if provided
    if cert_path:
        cert_path = Path(cert_path)
        if not cert_path.exists():
            raise ValueError(f"Certificate file not found: {cert_path}")
        if not cert_path.is_file():
            raise ValueError(f"Certificate path is not a file: {cert_path}")
    
    # Create configuration
    config = configparser.ConfigParser()
    
    # Global settings
    config['global'] = {
        'timeout': str(int(timeout)),
        'retries': str(int(retries)),
    }
    
    # Index URLs configuration
    config['install'] = {
        'index-url': internal_pypi_url,
    }
    
    if extra_index_urls:
        config['install']['extra-index-url'] = '\n' + '\n'.join(extra_index_urls)
    
    # Trusted hosts (only if explicitly provided and necessary)
    if validated_trusted_hosts:
        config['install']['trusted-host'] = '\n' + '\n'.join(validated_trusted_hosts)
    
    # Custom certificate if provided
    if cert_path:
        config['global']['cert'] = str(cert_path.absolute())
    
    # Get config file path
    config_path = get_pip_config_path()
    
    # Create directory with secure permissions
    config_path.parent.mkdir(parents=True, exist_ok=True)
    
    # Set restrictive permissions on config directory (Unix-like systems)
    if platform.system() != 'Windows':
        os.chmod(config_path.parent, 0o700)
    
    # Write configuration file
    with open(config_path, 'w') as f:
        config.write(f)
    
    # Set restrictive permissions on config file (Unix-like systems)
    if platform.system() != 'Windows':
        os.chmod(config_path, 0o600)
    
    return config_path


